    if not argv:
        sys.stderr.write(
            "Usage:\n"
            "  python app.py ping\n"
            "  python app.py doc-index --title ... --body ... [--tags a,b] [--source s] [--meta k=v ...]\n"
            "  python app.py doc-search --q ... [--tags a,b] [--source s] [--size N] [--from N]\n"
            "  python app.py log-emit --message ... [--level L] [--service S] [--logger L] [--tags a,b] [--field k=v ...]\n"
            "  python app.py log-search [--q ...] [--service S] [--level L] [--host H] [--logger L] [--trace-id T] [--tags a,b] [--start ISO] [--end ISO] [--size N] [--from N]\n"
            "  python app.py log-agg-levels --interval 1m [--service S] [--q ...] [--start ISO] [--end ISO]\n"
            "  python app.py log-agg-services [--start ISO] [--end ISO] [--size N]\n"
            "  python app.py log-agg-error-rate --interval 1m [--service S] [--start ISO] [--end ISO]\n"
        )
        return 2

    cmd = argv[0]
    args = argv[1:]

    es_url = os.getenv("ES_URL", DEFAULT_ES_URL)
    app = App(es_url)

    if cmd == "ping":
        ok = app.es_client.ping()
        _print_json({"ok": ok, "es_url": es_url})
        return 0 if ok else 1

    if cmd == "doc-index":
        title = ""
        body = ""
        tags: List[str] = []
        source = None
        meta_items: List[str] = []
